css:
    @import url("https://fontsapi.zeoseven.com/532/main/result.css");

    /* 全局主题颜色定义，方便管理 */
    :root {
        --cyber-blue: #00bfff; /* 科技蓝 */
        --cyber-purple: #8a2be2; /* 赛博紫 */
        --cyber-yellow: #ffd700; /* 点缀黄 */
        --text-color: #e0e0e0; /* 可读性高的浅灰色文本 */
        --border-color: #333; /* 深色边框 */
        --ui-background: rgba(36, 36, 37, 0.8); /* 半透明的深色UI背景 */
        /* 消息气泡的背景现在由 .mes_block 上的 user/bot_mes_blur_tint_color 控制 */
    }

    /* 替换全局字体 */
    body {
        font-family: "NanoDyongChyangSong CN 24", sans-serif;
        font-weight: normal;
        background-color: var(--ui-background);
        color: var(--text-color);
    }

    /* 被星号（*例如这样*）包裹的字体（通常是 `<em>` 标签） */
    em {
        font-family: "NanoDyongChyangSong CN 24", sans-serif;
        font-weight: normal;
    }

    /* 被引号包裹的字体（通常是 `<blockquote>` 标签） */
    blockquote {
        border: none; /* 移除所有边框 */
        background-color: rgba(0, 0, 0, 0.5); /* 半透明黑色背景 */
        padding: 10px;
        margin: 10px 0;
        color: var(--cyber-yellow); /* 引用文本颜色 */
        box-shadow: 0 0 10px var(--cyber-yellow); /* 黄色发光效果 */
    }

    /* 1. 最上方导航栏图标替换 */
    /* 隐藏 FontAwesome 图标，并为父元素设置背景图 */
    .drawer-icon.fa-solid,
    #options_button.fa-solid,
    #extensionsMenuButton.fa-solid,
    #send_but.fa-solid,
    #quick-reply-rocket-button.interactable {
        font-size: 0; /* 隐藏 FontAwesome 图标文本 */
        text-indent: -9999px; /* 将文本移出视口 */
        overflow: hidden;
        background-position: center;
        background-repeat: no-repeat;
        background-size: contain; /* 图片适应容器大小 */
        display: block; /* 确保元素占据空间 */
        width: 30px; /* 图标尺寸 */
        height: 30px; /* 图标尺寸 */
        min-width: 30px;
        min-height: 30px;
        padding: 5px; /* 图片周围留白 */
    }

    /* 顶部导航栏图标 - 关闭状态 */
    #leftNavDrawerIcon.closedIcon { background-image: url('https://files.catbox.moe/fcs1dm.png'); }
    #API-status-top.closedIcon { background-image: url('https://files.catbox.moe/meajnu.png'); }
    #advanced-formatting-button .drawer-icon.closedIcon { background-image: url('https://files.catbox.moe/427q60.png'); }
    #WIDrawerIcon.closedIcon { background-image: url('https://files.catbox.moe/c5662k.png'); }
    #user-settings-button .drawer-icon.closedIcon { background-image: url('https://files.catbox.moe/lw3vik.png'); }
    #extensions-settings-button .drawer-icon.closedIcon { background-image: url('https://files.catbox.moe/ml619m.png'); }
    #persona-management-button .drawer-icon.closedIcon { background-image: url('https://files.catbox.moe/isi2lr.png'); }
    #rightNavDrawerIcon.closedIcon { background-image: url('https://files.catbox.moe/55jvjd.png'); }
    #table_drawer_icon.closedIcon { background-image: url('https://files.catbox.moe/zl2qx0.png'); }

    /* 特定图标修复: "更改背景图片"图标 */
    div#site_logo .drawer-icon.closedIcon { background-image: url('https://files.catbox.moe/b66mga.png'); }

    /* 顶部导航栏图标 - 展开状态（当 .closedIcon 类被移除时） */
    .drawer-icon:not(.closedIcon) {
        background-image: url('https://files.catbox.moe/x9zvnh.png') !important; /* !important 强制覆盖特定图标 */
    }

    /* 2. 最下方图标替换 */
    #options_button { background-image: url('https://files.catbox.moe/10zdpy.png'); }
    #extensionsMenuButton { background-image: url('https://files.catbox.moe/i3u141.png'); }
    #send_but { background-image: url('https://files.catbox.moe/yznklm.png'); }
    #quick-reply-rocket-button { background-image: url('https://files.catbox.moe/tkfrwj.png'); }

    /* 3. 移除 AI 和 User 对话框内容的边框 */
    /* 通用消息气泡样式（AI和用户共有部分） */
    .mes_block {
        border: none; /* 移除所有边框 */
        padding: 15px; /* 消息气泡内部填充 */
        border-radius: 15px; /* 气泡圆角 */
        color: var(--text-color); /* 文本颜色 */
        box-shadow: 0 0 15px rgba(0, 191, 255, 0.3); /* 柔和的蓝色发光 */
        position: relative; /* 为伪元素定位做准备 */
        overflow: hidden; /* 隐藏溢出背景 */
        z-index: 1; /* 确保消息气泡内容在背景上方 */
    }

    /* AI 对话框内容背景 */
    .mes[is_user="false"] .mes_block {
        background-color: var(--bot-mes-blur_tint_color); /* AI消息气泡背景 */
    }

    /* User 对话框内容背景 */
    .mes[is_user="true"] .mes_block {
        background-color: var(--user-mes_blur_tint_color); /* 用户消息气泡背景 */
    }

    /* 5. 头像框及位置调整 */
    /* 头像框样式 */
    .avatar {
        position: relative; /* 为伪元素定位做准备 */
        overflow: hidden; /* 隐藏超出头像框部分 */
        border-radius: 50%; /* 圆形头像 */
        border: 2px solid var(--cyber-blue); /* 默认边框，可被伪元素覆盖 */
        box-shadow: 0 0 10px var(--cyber-blue); /* 蓝色发光效果 */
        width: 70px; /* 设定头像大小 */
        height: 70px; /* 设定头像大小 */
        display: flex; /* Flexbox布局，用于图片居中 */
        justify-content: center;
        align-items: center;
    }

    .avatar img {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: cover; /* 确保图片覆盖整个头像区域 */
        border-radius: 50%; /* 确保图片也是圆形 */
    }

    .avatar::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-image: url('https://files.catbox.moe/yqo6t0.gif');
        background-size: 100% 100%; /* GIF 图片自适应头像大小 */
        background-repeat: no-repeat;
        pointer-events: none; /* 允许点击穿透伪元素 */
        z-index: 1; /* 确保边框在图片上方 */
    }

    /* mesAvatarWrapper (包含头像和信息) 显示在 mes_block 上方，居中显示 */
    .mes {
        display: flex;
        flex-direction: column; /* 垂直堆叠子元素 */
        align-items: center; /* 水平居中 */
        margin-bottom: 20px; /* 消息之间留白 */
    }

    .mesAvatarWrapper {
        order: -1; /* 将 mesAvatarWrapper 放在 Flex 容器的第一个 */
        margin-bottom: 5px; /* 头像与消息气泡之间的间距 */
        display: flex;
        flex-direction: column; /* mesAvatarWrapper 内部元素垂直堆叠 */
        align-items: center; /* 内部元素水平居中 */
        width: fit-content; /* 宽度适应内容 */
    }

    /* mesIDDisplay, mes_timer, tokenCounterDisplay 在头像下一行并排显示 */
    /* 确保它们在头像下一行并排，并留有间距 */
    .mesAvatarWrapper .mesIDDisplay,
    .mesAvatarWrapper .mes_timer,
    .mesAvatarWrapper .tokenCounterDisplay {
        font-size: 0.8em; /* 信息文本小一点 */
        color: var(--cyber-blue); /* 科技蓝颜色 */
        background-color: rgba(0, 0, 0, 0.5); /* 半透明背景 */
        padding: 2px 5px;
        border-radius: 3px;
        white-space: nowrap; /* 防止换行 */
        display: inline-block; /* 使它们并排显示 */
        margin: 0 4px; /* 元素之间间距 */
    }

    /* 确保这三个信息显示在头像下方一行 */
    .mesAvatarWrapper > .avatar + div {
        display: flex;
        justify-content: center;
        gap: 8px;
        margin-top: 5px;
        flex-wrap: wrap;
    }


    /* 6. 消息气泡动态背景 */
    .mes_block::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-image: url('https://files.catbox.moe/3cgicb.gif');
        background-size: cover; /* GIF 覆盖整个消息气泡 */
        background-position: center bottom; /* 从底部居中对齐 */
        background-repeat: no-repeat;
        opacity: 0.2; /* 半透明效果，使背景更柔和 */
        z-index: -1; /* 将 GIF 放在文本下方 */
    }

    /* 确保消息文本在背景上方 */
    .mes_block .mes_text {
        position: relative;
        z-index: 2;
    }


   /* 消息气泡装饰图片（这部分是史山代码能跑就行，不懂的宝宝尽量别动） */
    .mes_block::after {
        content: '';
        position: absolute;
        top: 0; left: 0; /* 覆盖整个区域以进行多背景定位 */
        width: 100%; height: 100%;
        /* 消息框上下图片 */
        background-image: 
url('https://files.catbox.moe/8f41tu.png');
        /* 精确位置和内边距 */
        background-position: top 5px left 5px, bottom 5px right 5px;
        background-size: 700px 40px; 
background-position: center bottom;
/* 图片大小，可调整 */
        background-repeat: no-repeat;
        z-index: 0; /* 在GIF之上 (z-index -1), 在文本之下 (z-index 2) */
        pointer-events: none; /* 允许点击穿透 */
    }


    /* 通用UI元素调整以适应主题 */
    .menu_button, .api_button, .drawer-toggle, .drawer-content, .drawer-header {
        background-color: rgba(0, 0, 0, 0.6);
        border: 1px solid var(--cyber-blue);
        box-shadow: 0 0 5px var(--cyber-blue);
        color: var(--text-color);
        transition: all 0.3s ease-in-out; /* 添加过渡效果 */
    }

    .menu_button:hover, .api_button:hover, .drawer-toggle:hover {
        background-color: rgba(0, 0, 0, 0.8);
        box-shadow: 0 0 15px var(--cyber-purple);
        border-color: var(--cyber-purple);
        transform: translateY(-2px); /* 悬停时轻微上浮 */
    }

    .text_pole, textarea {
        background-color: rgba(0, 0, 0, 0.7);
        border: 1px solid var(--cyber-blue);
        color: var(--text-color);
        transition: border-color 0.3s ease-in-out, box-shadow 0.3s ease-in-out;
    }
    .text_pole:focus, textarea:focus {
        border-color: var(--cyber-purple);
        box-shadow: 0 0 8px var(--cyber-purple);
        outline: none; /* 移除默认焦点轮廓 */
    }

    /* 突出显示活动元素/选择 */
    .selected, .active {
        background-color: var(--cyber-purple) !important;
        border-color: var(--cyber-yellow) !important;
        box-shadow: 0 0 10px var(--cyber-yellow) !important;
    }

    /* 其他UI元素的背景和边框 */
    #top-bar, #sheld, #form_sheld, #options {
        background-color: rgba(36, 36, 37, 0.7);
        border-color: var(--cyber-blue);
    }

    .title_restorable strong, .standoutHeader strong {
        color: var(--cyber-yellow); /* 标题突出显示 */
    }

    /* 滚动条美化 */
    ::-webkit-scrollbar {
        width: 10px;
        height: 10px;
    }
    ::-webkit-scrollbar-track {
        background: rgba(0, 0, 0, 0.3);
        border-radius: 5px;
    }
    ::-webkit-scrollbar-thumb {
        background: var(--cyber-purple);
        border-radius: 5px;
        border: 1px solid var(--cyber-blue);
    }
    ::-webkit-scrollbar-thumb:hover {
        background: var(--cyber-yellow);
    }
    ::-webkit-scrollbar-corner {
        background: transparent;
    }

    /* 调整：#saved_regex_scripts 与右侧边框的空隙 */
    #saved_regex_scripts {
        padding-right: 15px; /* 或 margin-right: 15px; */
    }
    #saved_scoped_scripts {
        padding-right: 15px; /* 或 margin-right: 15px; */
    }

    /* 顶部导航栏背景图 */
    #top-settings-holder {
        background-image: url('https://files.catbox.moe/ibli6u.jpg');
        background-size: cover; /* 覆盖整个区域 */
        background-position: center top; /* 从顶部居中对齐 */
        background-repeat: no-repeat;
    }

    /* 修正：让消息框里的文字铺满消息框 */
    .mes_block .ch_name,
    .mes_block .mes_text {
        width: 100%; /* 确保元素占据父元素内容区的全部宽度 */
        box-sizing: border-box; /* 包含内边距和边框在宽度计算内 */
        margin: 0; /* 移除所有外部边距 */
        padding-left: 0; /* 移除可能存在的左侧内边距 */
        padding-right: 0; /* 移除可能存在的右侧内边距 */
    }

    /* 保持 .mes_text 的顶部内边距 */
    .mes_block .mes_text {
        padding-top: calc(var(--mainFontSize) * 0.8);
    }
